```mlir
firrtl.circuit "Foo"  {
  firrtl.nla @nla_5560 [#hw.innerNameRef<@Bar0::@leaf>, #hw.innerNameRef<@Leaf::@w>]
  firrtl.nla @nla_5561 [#hw.innerNameRef<@Bar1::@leaf>, #hw.innerNameRef<@Leaf::@w>]
  firrtl.module @Foo() {
    firrtl.instance bar0  @Bar0()
    firrtl.instance bar1  @Bar1()
  }
  firrtl.module @Bar0() {
    firrtl.instance leaf sym @leaf  {annotations = [{circt.nonlocal = @nla_5560, class = "circt.nonlocal"}]} @Leaf()
  }
  firrtl.module @Bar1() {
    firrtl.instance leaf sym @leaf  {annotations = [{circt.nonlocal = @nla_5561, class = "circt.nonlocal"}]} @Leaf()
  }
  firrtl.module @Leaf() attributes {annotations = [{class = "firrtl.passes.InlineAnnotation"}]} {
    %w = firrtl.wire sym @w  {annotations = [{circt.nonlocal = @nla_5560, class = "test0"}, {circt.nonlocal = @nla_5561, class = "test1"}]} : !firrtl.uint<8>
  }
}
```

`./bin/circt-opt --pass-pipeline='firrtl.circuit(firrtl-inliner)'  ./inline.mlir`
- Annotations with class `test0` and `test1` should not be in both locations
- There should not be a reference to `@nla_5560` anymore as it has been deleted.
```mlir
module {
  firrtl.circuit "Foo"  {
    firrtl.module @Foo() {
      firrtl.instance bar0  @Bar0()
      firrtl.instance bar1  @Bar1()
    }
    firrtl.module @Bar0() {
      %leaf_w = firrtl.wire sym @w  {annotations = [{class = "test0"}, {class = "test1"}]} : !firrtl.uint<8>
    }
    firrtl.module @Bar1() {
      %leaf_w = firrtl.wire sym @w  {annotations = [{circt.nonlocal = @nla_5560, class = "test0"}, {class = "test1"}]} : !firrtl.uint<8>
    }
  }
}
```
